// ════════════════════════════════════════════
//  LEXICON PROCESSING
// ════════════════════════════════════════════

// Sort terms longest-first to avoid partial matches
const LEX_TERMS = Object.keys(LEXICON).sort((a, b) => b.length - a.length);

function applyLexicon(str) {
  // Split on existing HTML tags so we only modify text nodes
  return str.split(/(<[^>]+>)/g).map((part, i) => {
    if (part.startsWith('<')) return part; // HTML tag — skip
    let t = part;
    LEX_TERMS.forEach(term => {
      const esc = term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      t = t.replace(new RegExp(`\\b(${esc})\\b`, 'gi'),
        `<span class="lexterm" data-key="${term}">$1</span>`);
    });
    return t;
  }).join('');
}

