function render() {
  // Header summary
  document.getElementById('header-summary').innerHTML = applyLexicon(SUMMARY_SHORT);
  document.getElementById('summary-full').innerHTML = applyLexicon(SUMMARY_FULL);

  const mount = document.getElementById('timeline-mount');

  ERAS.forEach((era, ei) => {
    // Events HTML
    const eventsHTML = era.events.map((ev, vi) => `
      <div class="event" id="ev-${ei}-${vi}">
        <div class="event-trigger" data-era="${ei}" data-ev="${vi}">
          <span class="event-year">${ev.year}</span>
          <span class="event-name">${ev.name}</span>
          <svg class="event-arrow" viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.5">
            <path d="M6 3l5 5-5 5"/>
          </svg>
        </div>
        <div class="event-detail" id="ev-detail-${ei}-${vi}">
          <div class="event-detail-inner">
            <p>${applyLexicon(ev.detail)}</p>
          </div>
        </div>
      </div>
    `).join('');

    // Rules HTML
    const rulesHTML = era.rules.map(r =>
      `<li><span class="rule-dash">—</span><span>${applyLexicon(r)}</span></li>`
    ).join('');

    // Transition
    const transHTML = era.transition ? `
      <div class="section transition-block">
        <div class="section-label">Transition Vector</div>
        <p class="section-body">${applyLexicon(era.transition)}</p>
      </div>
    ` : '';

    const el = document.createElement('div');
    el.className = 'era';
    el.id = `era-${ei}`;
    el.innerHTML = `
      <div class="era-spine">
        <div class="era-node" data-era="${ei}" title="Toggle era"></div>
      </div>
      <div class="era-card">
        <div class="era-header" data-era="${ei}">
          <div class="era-header-row">
            <span class="era-period">${era.years}</span>
            <span class="era-chevron">
              <span class="chevron-label">Expand</span>
              <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M3 6l5 5 5-5"/></svg>
            </span>
          </div>
          <div class="era-name">${era.name}</div>
          <p class="era-teaser">${era.teaser}</p>
        </div>
        <div class="era-body" id="era-body-${ei}">
          <div class="era-image-plate">
            <img src="${PLACEHOLDER_IMG}" alt="Field illustration — ${era.name}" />
            <span class="era-image-caption">Illustration — ${era.name} · ${era.years}</span>
          </div>
          <button class="sensory-trigger" data-era="${ei}">
            <div class="sensory-icon">◉</div>
            Sensory Profile — enter this era
          </button>
          <div class="section">
            <div class="section-label">Current Conditions</div>
            <p class="section-body">${applyLexicon(era.conditions)}</p>
          </div>
          <div class="section">
            <div class="section-label">The Rules</div>
            <ul class="rules-list">${rulesHTML}</ul>
          </div>
          <div class="section">
            <div class="section-label">Key Events</div>
            <div class="events-list">${eventsHTML}</div>
          </div>
          ${transHTML}
        </div>
      </div>
    `;
    mount.appendChild(el);
  });
}

// ════════════════════════════════════════════
//  ACCORDION HELPERS
// ════════════════════════════════════════════

function slideOpen(el) {
  el.classList.add('animating');
  el.style.height = '0';
  el.style.overflow = 'hidden';
  const h = el.scrollHeight;
  requestAnimationFrame(() => {
    el.style.transition = 'height 0.38s cubic-bezier(0.4,0,0.2,1)';
    el.style.height = h + 'px';
    function onDone(e) {
      if (e.target !== el || e.propertyName !== 'height') return;
      el.removeEventListener('transitionend', onDone);
      el.style.height = '';
      el.style.overflow = '';
      el.style.transition = '';
      el.classList.remove('animating');
      el.classList.add('open');
    }
    el.addEventListener('transitionend', onDone);
  });
}

function slideClose(el) {
  el.style.height = el.scrollHeight + 'px';
  el.style.overflow = 'hidden';
  requestAnimationFrame(() => {
    el.style.transition = 'height 0.32s cubic-bezier(0.4,0,0.2,1)';
    el.style.height = '0';
    function onDone(e) {
      if (e.target !== el || e.propertyName !== 'height') return;
      el.removeEventListener('transitionend', onDone);
      el.style.height = '';
      el.style.overflow = '';
      el.style.transition = '';
      el.classList.remove('animating', 'open');
    }
    el.addEventListener('transitionend', onDone);
  });
}

// ════════════════════════════════════════════
//  INTERACTIONS
// ════════════════════════════════════════════

function attachInteractions() {
  // Summary expand
  const summaryToggle = document.getElementById('summary-toggle');
  const summaryFull = document.getElementById('summary-full');
  let summaryOpen = false;
  summaryToggle.addEventListener('click', () => {
    summaryOpen = !summaryOpen;
    if (summaryOpen) {
      summaryFull.style.display = 'block';
      summaryToggle.textContent = 'Hide ↑';
    } else {
      summaryFull.style.display = 'none';
      summaryToggle.textContent = 'Read full summary ↓';
    }
  });

  // Era expand/collapse (header click or node click)
  document.addEventListener('click', e => {
    const header = e.target.closest('.era-header');
    const node   = e.target.closest('.era-node');
    if (!header && !node) return;
    if (e.target.closest('.sensory-trigger')) return;

    const eraIdx = parseInt((header || node).dataset.era);
    const eraEl  = document.getElementById(`era-${eraIdx}`);
    const body   = document.getElementById(`era-body-${eraIdx}`);
    const chevron = eraEl.querySelector('.chevron-label');
    const isOpen = eraEl.classList.contains('is-open');

    if (isOpen) {
      eraEl.classList.remove('is-open');
      chevron.textContent = 'Expand';
      slideClose(body);
    } else {
      eraEl.classList.add('is-open');
      chevron.textContent = 'Collapse';
      slideOpen(body);
    }
  });

  // Event expand/collapse
  document.addEventListener('click', e => {
    const trigger = e.target.closest('.event-trigger');
    if (!trigger) return;
    const ei = trigger.dataset.era;
    const vi = trigger.dataset.ev;
    const eventEl = document.getElementById(`ev-${ei}-${vi}`);
    const detail  = document.getElementById(`ev-detail-${ei}-${vi}`);
    const isOpen  = eventEl.classList.contains('is-open');

    if (isOpen) {
      eventEl.classList.remove('is-open');
      slideClose(detail);
    } else {
      eventEl.classList.add('is-open');
      slideOpen(detail);
    }
  });

  // Sensory drawer
  document.addEventListener('click', e => {
    const btn = e.target.closest('.sensory-trigger');
    if (!btn) return;
    e.stopPropagation();
    openDrawer(parseInt(btn.dataset.era));
  });

  document.getElementById('drawer-close').addEventListener('click', closeDrawer);
  document.getElementById('overlay').addEventListener('click', closeDrawer);
}

function openDrawer(eraIdx) {
  const era = ERAS[eraIdx];
  const s   = era.sensory;

  document.getElementById('drawer-era-name').textContent = `— ${era.name}`;
  document.getElementById('drawer-grid').innerHTML = [
    ['Acoustic',        s.acoustic],
    ['Optical',         s.optical],
    ['Atmospheric',     s.atmospheric],
    ['Tactile / Thermal', s.tactile]
  ].map(([label, text]) => `
    <div class="sensory-channel">
      <div class="channel-label">${label}</div>
      <p class="channel-text">${text}</p>
    </div>
  `).join('');

  document.getElementById('overlay').classList.add('open');
  document.getElementById('sensory-drawer').classList.add('open');
  document.body.style.overflow = 'hidden';
}

function closeDrawer() {
  document.getElementById('overlay').classList.remove('open');
  document.getElementById('sensory-drawer').classList.remove('open');
  document.body.style.overflow = '';
}

// ════════════════════════════════════════════
//  LEXICON TOOLTIP
// ════════════════════════════════════════════

function attachTooltips() {
  const tooltip   = document.getElementById('lex-tooltip');
  const ttFull    = document.getElementById('tt-fullname');
  const ttDef     = document.getElementById('tt-def');
  const ttCharge  = document.getElementById('tt-charge');
  let hideTimer;

  document.addEventListener('mouseover', e => {
    const el = e.target.closest('.lexterm');
    if (!el) return;
    clearTimeout(hideTimer);

    const key = el.dataset.key;
    // Find matching lexicon entry (case-insensitive key lookup)
    const entry = LEXICON[key] || LEXICON[Object.keys(LEXICON).find(k => k.toLowerCase() === key.toLowerCase())];
    if (!entry) return;

    ttFull.textContent   = entry.full;
    ttDef.textContent    = entry.def;
    ttCharge.textContent = entry.charge;
    tooltip.classList.add('visible');
    positionTip(e);
  });

  document.addEventListener('mousemove', e => {
    if (tooltip.classList.contains('visible')) positionTip(e);
  });

  document.addEventListener('mouseout', e => {
    if (!e.target.closest('.lexterm')) return;
    hideTimer = setTimeout(() => tooltip.classList.remove('visible'), 120);
  });

  function positionTip(e) {
    const pad = 18, tw = 270, th = tooltip.offsetHeight || 120;
    let x = e.clientX + pad;
    let y = e.clientY + pad;
    if (x + tw > window.innerWidth  - pad) x = e.clientX - tw - pad;
    if (y + th > window.innerHeight - pad) y = e.clientY - th - pad;
    tooltip.style.left = x + 'px';
    tooltip.style.top  = y + 'px';
  }
}

// ════════════════════════════════════════════
//  INIT
// ════════════════════════════════════════════
render();

// Set hero image
document.getElementById('hero-img').src = PLACEHOLDER_IMG;

// Close all accordion bodies via JS so CSS !important never fights inline styles
document.querySelectorAll('.era-body, .event-detail').forEach(el => {
  el.style.height = '0';
  el.style.overflow = 'hidden';
});

attachInteractions();
attachTooltips();